  "products.premium.title": { lv: "Epsom Sāls PREMIUM",      en: "Epsom Salt PREMIUM",      ru: "Соль Эпсома PREMIUM" },
  "products.premium.tag":   { lv: "Farmaceitiskā kvalitāte", en: "Pharmaceutical grade",    ru: "Фармацевтическое качество" },
  "products.premium.short": { lv: "Augstākās tīrības Epsom sāls – tas pats, ko izmantojam kabīnē.",  en: "Highest purity Epsom salt — the same we use in our cabin.", ru: "Соль Эпсома высшей чистоты — та же, что мы используем в кабине." },
  "products.premium.what":  { lv: "Farmaceitiskās kvalitātes magnija sulfāts (MgSO₄). Augstākā tīrības pakāpe, bezpiedevu. Tas pats produkts, kas atrodas mūsu floutinga kabīnē.", en: "Pharmaceutical grade magnesium sulfate (MgSO₄). Highest purity, no additives. The exact product used in our float cabin.", ru: "Магния сульфат фармацевтического качества (MgSO₄). Высшая степень чистоты, без добавок. Тот же продукт, что используется в нашей кабине." },
  "products.premium.use":   { lv: "Vanna mājās, pēdu vanna, sauna, ķermeņa iesaiņošana, sejas maskas. Ideāli pēc sporta vai smagas darba dienas.", en: "Home bath, foot soak, sauna, body wraps, face masks. Ideal after sport or a hard day at work.", ru: "Домашняя ванна, ванночка для ног, сауна, обёртывания тела, маски для лица. Идеально после спорта или тяжёлого рабочего дня." },
  "products.premium.dose":  { lv: "Vanna: 200–400 g uz pilnu vannu. Pēdu vanna: 100 g uz mazā baseinā. Iedarbībai – 20 minūtes.", en: "Bath: 200–400 g per full bath. Foot soak: 100 g in a basin. Allow 20 minutes to take effect.", ru: "Ванна: 200–400 г на полную ванну. Ванночка для ног: 100 г в таз. Время воздействия — 20 минут." },
  "products.premium.sizes": { lv: "1 kg, 3 kg, 5 kg. Cena pēc pieprasījuma.", en: "1 kg, 3 kg, 5 kg. Price on request.", ru: "1 кг, 3 кг, 5 кг. Цена по запросу." },

  "products.purified.title": { lv: "Epsom Sāls (Attīrīts)",  en: "Epsom Salt (Purified)",   ru: "Соль Эпсома (Очищенная)" },
  "products.purified.tag":   { lv: "Ikdienas lietošanai",    en: "For everyday use",        ru: "Для ежедневного использования" },
  "products.purified.short": { lv: "Attīrīts Epsom sāls mājas procedūrām par pieejamu cenu.", en: "Purified Epsom salt for home procedures at an accessible price.", ru: "Очищенная соль Эпсома для домашних процедур по доступной цене." },
  "products.purified.what":  { lv: "Attīrīts magnija sulfāts ikdienas ķermeņa kopšanai. Lielisks variants regulārai lietošanai mājās.", en: "Purified magnesium sulfate for everyday body care. A great option for regular home use.", ru: "Очищенный сульфат магния для ежедневного ухода за телом. Отличный вариант для регулярного домашнего использования." },
  "products.purified.use":   { lv: "Vanna, pēdu vanna, ķermeņa skrubis, matu maska. Viegli izšķīst ūdenī.", en: "Bath, foot soak, body scrub, hair mask. Dissolves easily in water.", ru: "Ванна, ванночка для ног, скраб для тела, маска для волос. Легко растворяется в воде." },
  "products.purified.dose":  { lv: "Vanna: 300–500 g. Skrubis: ņemiet nedaudz un berziet mitrā ādā pirms dušas.", en: "Bath: 300–500 g. Scrub: take a handful and rub into damp skin before showering.", ru: "Ванна: 300–500 г. Скраб: возьмите горсть и вотрите во влажную кожу перед душем." },
  "products.purified.sizes": { lv: "1 kg, 5 kg, 10 kg. Cena pēc pieprasījuma.", en: "1 kg, 5 kg, 10 kg. Price on request.", ru: "1 кг, 5 кг, 10 кг. Цена по запросу." },

  "products.cosmetics.title": { lv: "Magnija Sāls Kosmētika",  en: "Magnesium Salt Cosmetics", ru: "Магниевая Косметика" },
  "products.cosmetics.tag":   { lv: "Ķermeņa kopšana",        en: "Body care",               ru: "Уход за телом" },
  "products.cosmetics.short": { lv: "Magnija bāzēti ķermeņa kopšanas produkti ar tūlītēju iedarbību.", en: "Magnesium-based body care products with immediate effect.", ru: "Средства по уходу за телом на основе магния с мгновенным эффектом." },
  "products.cosmetics.what":  { lv: "Kosmētikas līnija uz magnija sāls bāzes – losjoni, skrubji un vannas produkti. Uzlabo ādas stāvokli un relaksē muskuļus.", en: "A cosmetics line based on magnesium salt — lotions, scrubs and bath products. Improves skin condition and relaxes muscles.", ru: "Косметическая линия на основе магниевой соли — лосьоны, скрабы и средства для ванны. Улучшает состояние кожи и расслабляет мышцы." },
  "products.cosmetics.use":   { lv: "Uzklājiet uz sausas vai mitras ādas, masējiet apļveida kustībās. Skalojiet ar siltu ūdeni.", en: "Apply to dry or damp skin, massage in circular motions. Rinse with warm water.", ru: "Нанесите на сухую или влажную кожу, массируйте круговыми движениями. Смойте тёплой водой." },
  "products.cosmetics.effect":{ lv: "Uzlabo asinsriti, mīkstina ādu, mazina muskuļu sasprindzinājumu. Jūtams efekts jau pēc pirmās lietošanas.", en: "Improves circulation, softens skin, reduces muscle tension. Noticeable effect after first use.", ru: "Улучшает кровообращение, смягчает кожу, снижает мышечное напряжение. Эффект ощутим уже после первого применения." },

